module adder_8bit
(
    input [7:0] a,
    input [7:0] b,
    input cin,
    output [7:0] sum,
    output cout
);
    wire [7:0] carry;

    assign {carry[0], sum[0]} = a[0] + b[0] + cin;
    genvar i;
    generate
        for (i = 1; i < 8; i = i + 1) begin : full_adder
            assign {carry[i], sum[i]} = a[i] + b[i] + carry[i-1];
        end
    endgenerate

    assign cout = carry[7];
endmodule
